  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Number of Requests per Minute per Client IP",
  "data": {
    "url": {
      "%context%": true,
      "%timefield%": "@timestamp",
      "index": "_all",
      "body": {
        "size": 0,
        "aggs": {
          "global_stats": {
            "scripted_metric": {
            "init_script": "state.counts = [:];",
            "map_script": " def minute = doc['@timestamp'].value.toInstant().truncatedTo(java.time.temporal.ChronoUnit.MINUTES).toString(); def client = doc['request.client_ip'].value; def key = minute + '||' + client; state.counts.put(key, state.counts.containsKey(key) ? state.counts.get(key) + 1 : 1); ",
            "combine_script": "return state.counts;",
            "reduce_script": " def merged = [:]; for (s in states) { for (entry in s.entrySet()) { def k = entry.getKey(); def v = entry.getValue(); merged.put(k, merged.containsKey(k) ? merged.get(k) + v : v); } } def countsList = new ArrayList(merged.values()); Collections.sort(countsList); def max = countsList.isEmpty() ? 0 : countsList[countsList.size() - 1]; def sum = 0; for (c in countsList) { sum += c; } def avg = countsList.isEmpty() ? 0 : sum / countsList.size(); def p95 = countsList.isEmpty() ? 0 : countsList[(int)(0.95 * (countsList.size() - 1))]; def p99 = countsList.isEmpty() ? 0 : countsList[(int)(0.99 * (countsList.size() - 1))]; return [ \"max\": max, \"avg\": avg, \"2x_avg\": 2*avg, \"p95\": p95, \"p99\": p99 ]; "
            }
          }
        }
      }
    },
    "format": { "property": "aggregations.global_stats.value" }
  },
  "transform": [
    {
      "fold": ["max", "avg", "2x_avg", "p95", "p99"],
      "as": ["stat", "value"]
    },
    {
      "calculate": "datum.stat === 'max' ? 'Maximum' : datum.stat === 'avg' ? 'Average' : datum.stat === '2x_avg' ? 'Double Average' : datum.stat === 'p95' ? '95th Percentile' : '99th Percentile'",
      "as": "stat_label"
    }
  ],
  "layer": [
    {
      "mark": {
        "type": "text",
        "y": 50,
        "align": "center",
        "fontSize": 20,
        "color": "#555555"
      },
      "encoding": {
        "x": {
          "field": "stat_label",
